  'quick.tokenCount': { zh: '{{count}} 个 Token', en: '{{count}} tokens', fr: '{{count}} jetons', ru: '{{count}} токенов', es: '{{count}} tokens', ja: '{{count}} トークン' },
  'quick.viewOutput': { zh: '查看会话输出', en: 'View session output', fr: 'Voir la sortie de session', ru: 'Показать результат сессии', es: 'Ver salida de la sesión', ja: 'セッション出力を表示' },
  'quick.blindRationale': { zh: '盲审理由', en: 'Blind judge rationale', fr: 'Justification du juge aveugle', ru: 'Обоснование слепого судьи', es: 'Justificación del juez ciego', ja: 'ブラインド判定の理由' },
  'quick.resultPrivacy': { zh: 'SkillOps 不会将任务文本、验收标准、生成答案或聊天写入磁盘。已保存的提供方设置可能存在于本地 data/ai-settings.json。未安装或提升任何 Skill。', en: 'SkillOps does not write task text, acceptance criteria, generated answers, or chat to disk. Saved provider settings may exist in local data/ai-settings.json. No Skill was installed or promoted.', fr: 'SkillOps n’écrit pas sur disque les tâches, critères, réponses générées ou chats. Les paramètres fournisseur enregistrés peuvent exister dans data/ai-settings.json. Aucun Skill n’a été installé ni promu.', ru: 'SkillOps не записывает на диск текст задачи, критерии, ответы или чат. Сохранённые настройки провайдера могут находиться в data/ai-settings.json. Ни один Skill не установлен и не продвинут.', es: 'SkillOps no escribe en disco tareas, criterios, respuestas generadas ni chats. La configuración guardada del proveedor puede existir en data/ai-settings.json. No se instaló ni promocionó ningún Skill.', ja: 'SkillOps はタスク本文、受け入れ基準、生成回答、チャットをディスクへ書き込みません。保存済みプロバイダー設定はローカルの data/ai-settings.json に存在する場合があります。Skill のインストールや昇格は行われていません。' },
  'quick.workspaceTitle': { zh: '比较新的开源 Skill', en: 'Compare a new open-source Skill', fr: 'Comparer un nouveau Skill open source', ru: 'Сравнить новый Skill с открытым кодом', es: 'Comparar un nuevo Skill de código abierto', ja: '新しいオープンソース Skill を比較' },
  'quick.workspaceDescription': { zh: '发现与已启用本地 Skill 的重叠，然后让两个定义执行相同任务并进行盲审。', en: 'Discover overlap with enabled local Skills, then run both definitions against the same task and blind judge.', fr: 'Détectez les chevauchements avec les Skills locaux actifs, puis exécutez les deux définitions sur la même tâche avec un juge aveugle.', ru: 'Найдите пересечения с активными локальными Skill, затем выполните оба определения на одной задаче со слепой оценкой.', es: 'Detecta coincidencias con los Skills locales habilitados y ejecuta ambas definiciones con la misma tarea y un juez ciego.', ja: '有効なローカル Skill との重複を確認し、両方の定義を同じタスクで実行してブラインド判定します。' },
  'quick.askSkillOps': { zh: '询问 SkillOps', en: 'Ask SkillOps', fr: 'Demander à SkillOps', ru: 'Спросить SkillOps', es: 'Preguntar a SkillOps', ja: 'SkillOps に質問' },
  'quick.assistantWelcome': { zh: '粘贴公开的 GitHub Skill URL。我可以帮助你理解最接近的本地匹配项和 A/B 结果，而不会更改任何已安装的 Skill。', en: 'Paste a public GitHub Skill URL. I can help you interpret its nearest local match and the A/B result without changing any installed Skill.', fr: 'Collez l’URL publique d’un Skill GitHub. Je peux expliquer sa correspondance locale la plus proche et le résultat A/B sans modifier les Skills installés.', ru: 'Вставьте публичный URL GitHub Skill. Я помогу понять ближайшее локальное совпадение и результат A/B, не изменяя установленные Skill.', es: 'Pega la URL pública de un Skill de GitHub. Puedo explicar la coincidencia local más cercana y el resultado A/B sin cambiar ningún Skill instalado.', ja: '公開 GitHub Skill URL を貼り付けてください。インストール済み Skill を変更せず、最も近いローカル候補と A/B 結果を説明できます。' },
  'quick.analysisFailed': { zh: '候选版本分析失败。', en: 'Candidate analysis failed.', fr: 'L’analyse du candidat a échoué.', ru: 'Не удалось проанализировать кандидата.', es: 'Falló el análisis del candidato.', ja: '候補の分析に失敗しました。' },
  'quick.evaluationFailed': { zh: 'A/B 评测失败。', en: 'A/B evaluation failed.', fr: 'L’évaluation A/B a échoué.', ru: 'Оценка A/B завершилась ошибкой.', es: 'Falló la evaluación A/B.', ja: 'A/B 評価に失敗しました。' },
  'quick.assistantFailed': { zh: '助手请求失败。', en: 'Assistant request failed.', fr: 'La requête à l’assistant a échoué.', ru: 'Запрос к помощнику завершился ошибкой.', es: 'Falló la solicitud al asistente.', ja: 'アシスタントへのリクエストに失敗しました。' },
