  'quick.explainOverlapPrompt': { zh: '解释重叠部分', en: 'Explain the overlap', fr: 'Expliquer le chevauchement', ru: 'Объяснить пересечение', es: 'Explicar la coincidencia', ja: '重複を説明' },
