  'quick.whyWinner': { zh: '为什么这个版本胜出？', en: 'Why did this version win?', fr: 'Pourquoi cette version a-t-elle gagné ?', ru: 'Почему победила эта версия?', es: '¿Por qué ganó esta versión?', ja: 'このバージョンが勝った理由は？' },
  'quick.testNext': { zh: '接下来应该测试什么？', en: 'What should I test next?', fr: 'Que dois-je tester ensuite ?', ru: 'Что проверить дальше?', es: '¿Qué debería probar después?', ja: '次に何をテストすべきですか？' },
