  'ai.settingsDescription': { zh: '配置用于聊天和 A/B 评测的模型。', en: 'Configure the model used for chat and A/B evaluation.', fr: 'Configurez le modèle utilisé pour le chat et l’évaluation A/B.', ru: 'Настройте модель для чата и A/B-оценки.', es: 'Configura el modelo usado para el chat y la evaluación A/B.', ja: 'チャットと A/B 評価に使用するモデルを設定します。' },
