  'ai.savedKeyNote': { zh: '保存后，API 密钥会写入本地 SkillOps 数据文件。', en: 'Saved API keys are written to the local SkillOps data file.', fr: 'Les clés API enregistrées sont écrites dans le fichier de données SkillOps local.', ru: 'Сохранённые API-ключи записываются в локальный файл данных SkillOps.', es: 'Las claves API guardadas se escriben en el archivo de datos local de SkillOps.', ja: '保存した API キーはローカルの SkillOps データファイルに書き込まれます。' },
  'ai.ollamaHelper': { zh: '无需 API 密钥。SkillOps 通过回环 Ollama 端点连接。', en: 'No API key is required. SkillOps connects through the loopback Ollama endpoint.', fr: 'Aucune clé API n’est requise. SkillOps se connecte au point de terminaison Ollama en boucle locale.', ru: 'API-ключ не требуется. SkillOps подключается к локальному endpoint Ollama.', es: 'No se requiere clave API. SkillOps se conecta mediante el endpoint local de Ollama.', ja: 'API キーは不要です。SkillOps はループバックの Ollama エンドポイントに接続します。' },
  'ai.providerHelper': { zh: '密钥仅通过回环 SkillOps API 发送给所选提供方。', en: 'The key is sent only through the loopback SkillOps API to the selected provider.', fr: 'La clé est envoyée au fournisseur sélectionné uniquement via l’API SkillOps en boucle locale.', ru: 'Ключ отправляется выбранному провайдеру только через локальный API SkillOps.', es: 'La clave solo se envía al proveedor seleccionado mediante la API local de SkillOps.', ja: 'キーはループバック SkillOps API 経由で選択したプロバイダーにのみ送信されます。' },
